  1	import { List as ImmutableList, Map as ImmutableMap } from 'immutable';
  2	import { defer, omit, uniqueId } from 'lodash';
  3	import * as React from 'react';
  4	import { useTranslation } from 'react-i18next';
  5	import Markdown from 'react-markdown';
  6	import { useDispatch, useSelector } from 'react-redux';
  7	import { consoleFetch } from '@openshift-console/dynamic-plugin-sdk';
  8	import {
  9	  Alert,
 10	  Badge,
 11	  Button,
 12	  CodeBlock,
 13	  CodeBlockAction,
 14	  CodeBlockCode,
 15	  ExpandableSection,
 16	  Form,
 17	  HelperText,
 18	  HelperTextItem,
 19	  Label,
 20	  LabelGroup,
 21	  Level,
 22	  LevelItem,
 23	  Page,
 24	  PageSection,
 25	  Spinner,
 26	  Split,
 27	  SplitItem,
 28	  TextArea,
 29	  Title,
 30	} from '@patternfly/react-core';
 31	import {
 32	  CompressIcon,
 33	  ExpandIcon,
 34	  ExternalLinkAltIcon,
 35	  PaperPlaneIcon,
 36	  StopIcon,
 37	  WindowMinimizeIcon,
 38	} from '@patternfly/react-icons';
 39	
 40	import { toOLSAttachment } from '../attachments';
 41	import { getApiUrl } from '../config';
 42	import { getFetchErrorMessage } from '../error';
 43	import { AuthStatus, getRequestInitWithAuthHeader, useAuth } from '../hooks/useAuth';
 44	import { useBoolean } from '../hooks/useBoolean';
 45	import {
 46	  attachmentDelete,
 47	  attachmentsClear,
 48	  chatHistoryClear,
 49	  chatHistoryPush,
 50	  chatHistoryUpdateByID,
 51	  chatHistoryUpdateTool,
 52	  setConversationID,
 53	  setQuery,
 54	} from '../redux-actions';
 55	import { State } from '../redux-reducers';
 56	import { Attachment, ChatEntry, ReferencedDoc } from '../types';
 57	import AttachmentModal from './AttachmentModal';
 58	import AttachMenu from './AttachMenu';
 59	import AttachmentLabel from './AttachmentLabel';
 60	import AttachmentsSizeAlert from './AttachmentsSizeAlert';
 61	import CopyAction from './CopyAction';
 62	import ImportAction from './ImportAction';
 63	import Feedback from './Feedback';
 64	import NewChatModal from './NewChatModal';
 65	import ReadinessAlert from './ReadinessAlert';
 66	import ResponseTools from './ResponseTools';
 67	import ToolModal from './ResponseToolModal';
 68	
 69	import './general-page.css';
 70	
 71	const QUERY_ENDPOINT = getApiUrl('/v1/streaming_query');
 72	
 73	type QueryResponseStart = {
 74	  event: 'start';
 75	  data: {
 76	    conversation_id: string;
 77	  };
 78	};
 79	
 80	type QueryResponseToken = {
 81	  event: 'token';
 82	  data: {
 83	    id: number;
 84	    token: string;
 85	  };
 86	};
 87	
 88	type QueryResponseError = {
 89	  event: 'error';
 90	  data: {
 91	    response: string;
 92	    cause: string;
 93	  };
 94	};
 95	
 96	type QueryResponseEnd = {
 97	  event: 'end';
 98	  data: {
 99	    referenced_documents: Array<ReferencedDoc>;
100	    truncated: boolean;
101	  };
102	};
103	
104	type QueryResponseToolRequest = {
105	  event: 'tool_call';
106	  data: {
107	    args: { [key: string]: Array<string> };
108	    id: string;
109	    name: string;
110	  };
111	};
112	
113	type QueryResponseToolExecution = {
114	  event: 'tool_result';
115	  data: {
116	    content: string;
117	    id: string;
118	    status: 'error' | 'success';
119	  };
120	};
121	
122	type QueryResponse =
123	  | QueryResponseStart
124	  | QueryResponseToken
125	  | QueryResponseError
126	  | QueryResponseEnd
127	  | QueryResponseToolRequest
128	  | QueryResponseToolExecution;
129	
130	type ExternalLinkProps = {
131	  children: React.ReactNode;
132	  href: string;
133	};
134	
135	const ExternalLink: React.FC<ExternalLinkProps> = ({ children, href }) => (
136	  <a href={href} rel="noopener noreferrer" target="_blank">
137	    {children} <ExternalLinkAltIcon />
138	  </a>
139	);
140	
141	const isURL = (s: string): boolean => {
142	  try {
143	    const url = new URL(s);
144	    return !!(url.protocol && url.host);
145	  } catch {
146	    return false;
147	  }
148	};
149	
150	type ReferenceDocsProps = {
151	  references: Array<ReferencedDoc>;
152	};
153	
154	const ReferenceDocs: React.FC<ReferenceDocsProps> = ({ references }) => {
155	  let validReferences: Array<ReferencedDoc> = [];
156	  if (Array.isArray(references)) {
157	    validReferences = references.filter(
158	      (r) =>
159	        r && typeof r.doc_title === 'string' && typeof r.doc_url === 'string' && isURL(r.doc_url),
160	    );
161	  }
162	
163	  if (validReferences.length === 0) {
164	    return null;
165	  }
166	
167	  return (
168	    <div className="ols-plugin__references">
169	      <LabelGroup categoryName="Related documentation">
170	        {validReferences.map((r, i) => (
171	          <Label key={i} textMaxWidth="16rem">
172	            <ExternalLink href={r.doc_url}>{r.doc_title}</ExternalLink>
173	          </Label>
174	        ))}
175	      </LabelGroup>
176	    </div>
177	  );
178	};
179	
180	const Code = ({ children }: { children: React.ReactNode }) => {
181	  if (!String(children).includes('\n')) {
182	    return <code>{children}</code>;
183	  }
184	
185	  return (
186	    <CodeBlock
187	      actions={
188	        <CodeBlockAction>
189	          <CopyAction value={children.toString()} />
190	          <ImportAction value={children.toString()} />
191	        </CodeBlockAction>
192	      }
193	      className="ols-plugin__code-block"
194	    >
195	      <CodeBlockCode className="ols-plugin__code-block-code">{children}</CodeBlockCode>
196	    </CodeBlock>
197	  );
198	};
199	
200	type ChatHistoryEntryProps = {
201	  conversationID: string;
202	  entry: ChatEntry;
203	  entryIndex: number;
204	};
205	
206	const ChatHistoryEntry: React.FC<ChatHistoryEntryProps> = ({
207	  conversationID,
208	  entry,
209	  entryIndex,
210	}) => {
211	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
212	
213	  const [isContextExpanded, toggleContextExpanded] = useBoolean(false);
214	  const isUserFeedbackEnabled = useSelector((s: State) =>
215	    s.plugins?.ols?.get('isUserFeedbackEnabled'),
216	  );
217	
218	  if (entry.who === 'ai') {
219	    return (
220	      <div className="ols-plugin__chat-entry ols-plugin__chat-entry--ai">
221	        <div className="ols-plugin__chat-entry-name">OpenShift Lightspeed</div>
222	        {entry.error ? (
223	          <Alert
224	            isExpandable={!!entry.error.moreInfo}
225	            isInline
226	            title={
227	              entry.error.moreInfo
228	                ? entry.error.message
229	                : t('Error querying OpenShift Lightspeed service')
230	            }
231	            variant="danger"
232	          >
233	            {entry.error.moreInfo ? entry.error.moreInfo : entry.error.message}
234	          </Alert>
235	        ) : (
236	          <>
237	            <Markdown components={{ code: Code }}>{entry.text}</Markdown>
238	            {!entry.text && !entry.isCancelled && (
239	              <HelperText>
240	                <HelperTextItem variant="indeterminate">
241	                  {t('Waiting for LLM provider...')} <Spinner size="lg" />
242	                </HelperTextItem>
243	              </HelperText>
244	            )}
245	            {entry.isTruncated && (
246	              <Alert isInline title={t('History truncated')} variant="warning">
247	                {t('Conversation history has been truncated to fit within context window.')}
248	              </Alert>
249	            )}
250	            {entry.isCancelled && (
251	              <Alert
252	                className="ols-plugin__chat-entry-cancelled"
253	                isInline
254	                isPlain
255	                title={t('Cancelled')}
256	                variant="info"
257	              />
258	            )}
259	            {entry.tools && <ResponseTools entryIndex={entryIndex} />}
260	            <ReferenceDocs references={entry.references} />
261	            {isUserFeedbackEnabled && !entry.isStreaming && entry.text && (
262	              <Feedback conversationID={conversationID} entryIndex={entryIndex} />
263	            )}
264	          </>
265	        )}
266	      </div>
267	    );
268	  }
269	  if (entry.who === 'user') {
270	    return (
271	      <div className="ols-plugin__chat-entry ols-plugin__chat-entry--user">
272	        <div className="ols-plugin__chat-entry-name">You</div>
273	        <div className="ols-plugin__chat-entry-text">{entry.text}</div>
274	        {entry.attachments && Object.keys(entry.attachments).length > 0 && (
275	          <ExpandableSection
276	            className="ols-plugin__chat-history-context"
277	            displaySize="lg"
278	            isExpanded={isContextExpanded}
279	            onToggle={toggleContextExpanded}
280	            toggleContent={
281	              <>
282	                Context <Badge>{Object.keys(entry.attachments).length}</Badge>
283	              </>
284	            }
285	          >
286	            {Object.keys(entry.attachments).map((key: string) => {
287	              const attachment: Attachment = entry.attachments[key];
288	              return <AttachmentLabel attachment={attachment} key={key} />;
289	            })}
290	          </ExpandableSection>
291	        )}
292	      </div>
293	    );
294	  }
295	  return null;
296	};
297	
298	type AuthAlertProps = {
299	  authStatus: AuthStatus;
300	};
301	
302	const AuthAlert: React.FC<AuthAlertProps> = ({ authStatus }) => {
303	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
304	
305	  if (authStatus === AuthStatus.NotAuthenticated) {
306	    return (
307	      <Alert className="ols-plugin__alert" isInline title={t('Not authenticated')} variant="danger">
308	        {t(
309	          'OpenShift Lightspeed authentication failed. Contact your system administrator for more information.',
310	        )}
311	      </Alert>
312	    );
313	  }
314	
315	  if (authStatus === AuthStatus.NotAuthorized) {
316	    return (
317	      <Alert className="ols-plugin__alert" isInline title={t('Not authorized')} variant="danger">
318	        {t(
319	          'You do not have sufficient permissions to access OpenShift Lightspeed. Contact your system administrator for more information.',
320	        )}
321	      </Alert>
322	    );
323	  }
324	
325	  return null;
326	};
327	
328	const PrivacyAlert: React.FC = () => {
329	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
330	
331	  return (
332	    <Alert className="ols-plugin__alert" isInline title={t('Important')} variant="info">
333	      {t(
334	        "OpenShift Lightspeed uses AI technology to help answer your questions. Do not include personal information or other sensitive information in your input. Interactions may be used to improve Red Hat's products or services.",
335	      )}
336	    </Alert>
337	  );
338	};
339	
340	const Welcome: React.FC = () => {
341	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
342	
343	  return (
344	    <>
345	      <div className="ols-plugin__welcome-logo"></div>
346	      <Title className="pf-v6-u-text-align-center" headingLevel="h1">
347	        {t('Red Hat OpenShift Lightspeed')}
348	      </Title>
349	      <Title className="ols-plugin__welcome-subheading pf-v6-u-text-align-center" headingLevel="h4">
350	        {t(
351	          'Explore deeper insights, engage in meaningful discussions, and unlock new possibilities with Red Hat OpenShift Lightspeed. Answers are provided by generative AI technology, please use appropriate caution when following recommendations.',
352	        )}
353	      </Title>
354	    </>
355	  );
356	};
357	
358	type GeneralPageProps = {
359	  onClose: () => void;
360	  onCollapse?: () => void;
361	  onExpand?: () => void;
362	};
363	
364	const GeneralPage: React.FC<GeneralPageProps> = ({ onClose, onCollapse, onExpand }) => {
365	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
366	
367	  const dispatch = useDispatch();
368	
369	  const attachments = useSelector((s: State) => s.plugins?.ols?.get('attachments'));
370	  const chatHistory: ImmutableList<ImmutableMap<string, unknown>> = useSelector((s: State) =>
371	    s.plugins?.ols?.get('chatHistory'),
372	  );
373	
374	  const conversationID: string = useSelector((s: State) => s.plugins?.ols?.get('conversationID'));
375	  const query: string = useSelector((s: State) => s.plugins?.ols?.get('query'));
376	
377	  const [validated, setValidated] = React.useState<'default' | 'error'>('default');
378	
379	  const [streamController, setStreamController] = React.useState(new AbortController());
380	
381	  const [authStatus] = useAuth();
382	
383	  const [isNewChatModalOpen, , openNewChatModal, closeNewChatModal] = useBoolean(false);
384	
385	  const chatHistoryEndRef = React.useRef(null);
386	  const promptRef = React.useRef(null);
387	
388	  const scrollIntoView = React.useCallback((behavior = 'smooth') => {
389	    defer(() => {
390	      chatHistoryEndRef?.current?.scrollIntoView({ behavior });
391	    });
392	  }, []);
393	
394	  // Scroll to bottom of chat after first render (when opening UI that already has chat history)
395	  React.useEffect(() => {
396	    scrollIntoView('instant');
397	    // eslint-disable-next-line react-hooks/exhaustive-deps
398	  }, []);
399	
400	  const clearChat = React.useCallback(() => {
401	    dispatch(setConversationID(null));
402	    dispatch(chatHistoryClear());
403	    dispatch(attachmentsClear());
404	  }, [dispatch]);
405	
406	  const onChange = React.useCallback(
407	    (_e, value) => {
408	      if (value.trim().length > 0) {
409	        setValidated('default');
410	      }
411	      dispatch(setQuery(value));
412	    },
413	    [dispatch],
414	  );
415	
416	  const isStreaming = !!chatHistory.last()?.get('isStreaming');
417	
418	  const onSubmit = React.useCallback(
419	    (e) => {
420	      e.preventDefault();
421	
422	      if (isStreaming) {
423	        return;
424	      }
425	
426	      if (!query || query.trim().length === 0) {
427	        setValidated('error');
428	        return;
429	      }
430	
431	      dispatch(
432	        chatHistoryPush({
433	          attachments: attachments.map((a) => omit(a, 'originalValue')),
434	          text: query,
435	          who: 'user',
436	        }),
437	      );
438	      const chatEntryID = uniqueId('ChatEntry_');
439	      dispatch(
440	        chatHistoryPush({
441	          id: chatEntryID,
442	          isCancelled: false,
443	          isStreaming: true,
444	          isTruncated: false,
445	          references: [],
446	          text: '',
447	          tools: ImmutableMap(),
448	          who: 'ai',
449	        }),
450	      );
451	      scrollIntoView();
452	
453	      const requestJSON = {
454	        attachments: attachments.valueSeq().map(toOLSAttachment),
455	        // eslint-disable-next-line camelcase
456	        conversation_id: conversationID,
457	        // eslint-disable-next-line camelcase
458	        media_type: 'application/json',
459	        query,
460	      };
461	
462	      const streamResponse = async () => {
463	        const controller = new AbortController();
464	        setStreamController(controller);
465	        const response = await consoleFetch(QUERY_ENDPOINT, {
466	          method: 'POST',
467	          headers: Object.assign({}, getRequestInitWithAuthHeader().headers, {
468	            'Content-Type': 'application/json',
469	          }),
470	          body: JSON.stringify(requestJSON),
471	          signal: controller.signal,
472	        });
473	        if (response.ok === false) {
474	          dispatch(
475	            chatHistoryUpdateByID(chatEntryID, {
476	              error: getFetchErrorMessage({ response }, t),
477	              isStreaming: false,
478	              isTruncated: false,
479	              who: 'ai',
480	            }),
481	          );
482	          return;
483	        }
484	        const reader = response.body.getReader();
485	        const decoder = new TextDecoder();
486	        let responseText = '';
487	        // eslint-disable-next-line no-constant-condition
488	        while (true) {
489	          const { value, done } = await reader.read();
490	          if (done) {
491	            break;
492	          }
493	          const text = decoder.decode(value);
494	          text
495	            .split('\n')
496	            .filter((s) => s.startsWith('data: '))
497	            .forEach((s) => {
498	              const line = s.slice(5).trim();
499	              let json: QueryResponse;
500	              try {
501	                json = JSON.parse(line);
502	              } catch (error) {
503	                // eslint-disable-next-line no-console
504	                console.error(`Failed to parse JSON string "${line}"`, error);
505	              }
506	              if (json && json.event && json.data) {
507	                if (json.event === 'start') {
508	                  dispatch(setConversationID(json.data.conversation_id));
509	                } else if (json.event === 'token') {
510	                  responseText += json.data.token;
511	                  dispatch(chatHistoryUpdateByID(chatEntryID, { text: responseText }));
512	                } else if (json.event === 'end') {
513	                  dispatch(
514	                    chatHistoryUpdateByID(chatEntryID, {
515	                      isStreaming: false,
516	                      isTruncated: json.data.truncated === true,
517	                      references: json.data.referenced_documents,
518	                    }),
519	                  );
520	                } else if (json.event === 'tool_call') {
521	                  const { args, id, name } = json.data;
522	                  dispatch(chatHistoryUpdateTool(chatEntryID, id, { name, args }));
523	                } else if (json.event === 'tool_result') {
524	                  const { content, id, status } = json.data;
525	                  dispatch(chatHistoryUpdateTool(chatEntryID, id, { content, status }));
526	                } else if (json.event === 'error') {
527	                  dispatch(
528	                    chatHistoryUpdateByID(chatEntryID, {
529	                      error: getFetchErrorMessage({ json: { detail: json.data } }, t),
530	                      isStreaming: false,
531	                    }),
532	                  );
533	                } else {
534	                  // eslint-disable-next-line no-console
535	                  console.warn(`Unrecognized event in response stream:`, JSON.stringify(json));
536	                }
537	              }
538	            });
539	        }
540	      };
541	      streamResponse().catch((error) => {
542	        if (error.name !== 'AbortError') {
543	          dispatch(
544	            chatHistoryUpdateByID(chatEntryID, {
545	              error: getFetchErrorMessage(error, t),
546	              isStreaming: false,
547	              isTruncated: false,
548	              who: 'ai',
549	            }),
550	          );
551	        }
552	        scrollIntoView();
553	      });
554	
555	      // Clear prompt input and return focus to it
556	      dispatch(setQuery(''));
557	      dispatch(attachmentsClear());
558	      promptRef.current?.focus();
559	    },
560	    [attachments, conversationID, dispatch, isStreaming, query, scrollIntoView, t],
561	  );
562	
563	  const streamingResponseID: string = isStreaming
564	    ? (chatHistory.last()?.get('id') as string)
565	    : undefined;
566	  const onStreamCancel = React.useCallback(
567	    (e) => {
568	      e.preventDefault();
569	      if (streamingResponseID) {
570	        streamController.abort();
571	        dispatch(
572	          chatHistoryUpdateByID(streamingResponseID, {
573	            isCancelled: true,
574	            isStreaming: false,
575	          }),
576	        );
577	      }
578	    },
579	    [dispatch, streamController, streamingResponseID],
580	  );
581	
582	  // We use keypress instead of keydown even though keypress is deprecated to work around a problem
583	  // with IME (input method editor) input. A cleaner solution would be to use the isComposing
584	  // property, but unfortunately the Safari implementation differs making it unusable for our case.
585	  const onKeyPress = React.useCallback(
586	    (e) => {
587	      // Enter key alone submits the prompt, Shift+Enter inserts a newline
588	      if (e.key === 'Enter' && !e.shiftKey) {
589	        e.preventDefault();
590	        onSubmit(e);
591	      }
592	    },
593	    [onSubmit],
594	  );
595	
596	  const onConfirmNewChat = React.useCallback(() => {
597	    clearChat();
598	    closeNewChatModal();
599	  }, [clearChat, closeNewChatModal]);
600	
601	  const isWelcomePage = chatHistory.size === 0;
602	
603	  return (
604	    <Page>
605	      <PageSection className={isWelcomePage ? undefined : 'ols-plugin__header'} variant="light">
606	        {onExpand && (
607	          <Button
608	            className="ols-plugin__popover-control"
609	            onClick={onExpand}
610	            title={t('Expand')}
611	            variant="plain"
612	          >
613	            <ExpandIcon />
614	          </Button>
615	        )}
616	        {onCollapse && (
617	          <Button
618	            className="ols-plugin__popover-control"
619	            onClick={onCollapse}
620	            title={t('Collapse')}
621	            variant="plain"
622	          >
623	            <CompressIcon />
624	          </Button>
625	        )}
626	        <Button
627	          className="ols-plugin__popover-control"
628	          onClick={onClose}
629	          title={t('Minimize')}
630	          variant="plain"
631	        >
632	          <WindowMinimizeIcon />
633	        </Button>
634	        {!isWelcomePage && (
635	          <Level>
636	            <LevelItem>
637	              <Title className="ols-plugin__heading" headingLevel="h1">
638	                {t('Red Hat OpenShift Lightspeed')}
639	              </Title>
640	            </LevelItem>
641	            <LevelItem>
642	              <Button
643	                className="ols-plugin__popover-clear-chat"
644	                onClick={openNewChatModal}
645	                variant="primary"
646	              >
647	                {t('Clear chat')}
648	              </Button>
649	            </LevelItem>
650	          </Level>
651	        )}
652	      </PageSection>
653	
654	      <PageSection
655	        aria-label={t('OpenShift Lightspeed chat history')}
656	        className="ols-plugin__chat-history"
657	        hasOverflowScroll
658	        isFilled
659	        variant="light"
660	      >
661	        {isWelcomePage && <Welcome />}
662	        <AuthAlert authStatus={authStatus} />
663	        <PrivacyAlert />
664	        {chatHistory.toJS().map((entry: ChatEntry, i: number) => (
665	          <ChatHistoryEntry conversationID={conversationID} entry={entry} entryIndex={i} key={i} />
666	        ))}
667	        <AttachmentsSizeAlert />
668	        <ReadinessAlert />
669	        <div ref={chatHistoryEndRef} />
670	      </PageSection>
671	
672	      {authStatus !== AuthStatus.NotAuthenticated && authStatus !== AuthStatus.NotAuthorized && (
673	        <PageSection className="ols-plugin__chat-prompt" isFilled={false} variant="light">
674	          <Form onSubmit={isStreaming ? onStreamCancel : onSubmit}>
675	            <Split hasGutter>
676	              <SplitItem>
677	                <AttachMenu />
678	              </SplitItem>
679	              <SplitItem isFilled>
680	                <TextArea
681	                  aria-label={t('OpenShift Lightspeed prompt')}
682	                  autoFocus
683	                  className="ols-plugin__chat-prompt-input"
684	                  onChange={onChange}
685	                  onFocus={(e) => {
686	                    // Move cursor to the end of the text when popover is closed then reopened
687	                    const len = e.currentTarget?.value?.length;
688	                    if (len) {
689	                      e.currentTarget.setSelectionRange(len, len);
690	                    }
691	                  }}
692	                  onKeyPress={onKeyPress}
693	                  placeholder={t('Send a message...')}
694	                  ref={promptRef}
695	                  resizeOrientation="vertical"
696	                  rows={Math.min(query.split('\n').length, 12)}
697	                  validated={validated}
698	                  value={query}
699	                />
700	              </SplitItem>
701	              <SplitItem className="ols-plugin__chat-prompt-submit">
702	                <Button className="ols-plugin__chat-prompt-button" type="submit" variant="primary">
703	                  {isStreaming ? <StopIcon /> : <PaperPlaneIcon />}
704	                </Button>
705	              </SplitItem>
706	            </Split>
707	          </Form>
708	          <div className="ols-plugin__chat-prompt-attachments">
