621	            variant="plain"
622	          />
623	        )}
624	        <Button
625	          className="ols-plugin__popover-control"
626	          icon={<WindowMinimizeIcon />}
627	          onClick={onClose}
628	          title={t('Minimize')}
629	          variant="plain"
630	        />
631	        {!isWelcomePage && (
632	          <Level>
633	            <LevelItem>
634	              <Title className="ols-plugin__heading" headingLevel="h1">
