640	                className="ols-plugin__popover-clear-chat"
641	                onClick={openNewChatModal}
642	                variant="primary"
643	              >
644	                {t('Clear chat')}
645	              </Button>
646	            </LevelItem>
647	          </Level>
648	        )}
649	      </PageSection>
650	
651	      <PageSection
652	        aria-label={t('OpenShift Lightspeed chat history')}
653	        className="ols-plugin__chat-history"
654	        hasOverflowScroll
655	        isFilled
656	        variant="default"
657	      >
658	        {isWelcomePage && <Welcome />}
