668	
669	      {authStatus !== AuthStatus.NotAuthenticated && authStatus !== AuthStatus.NotAuthorized && (
670	        <PageSection className="ols-plugin__chat-prompt" isFilled={false} variant="default">
671	          <Form onSubmit={isStreaming ? onStreamCancel : onSubmit}>
672	            <Split hasGutter>
673	              <SplitItem>
674	                <AttachMenu />
675	              </SplitItem>
676	              <SplitItem isFilled>
677	                <TextArea
678	                  aria-label={t('OpenShift Lightspeed prompt')}
679	                  autoFocus
680	                  className="ols-plugin__chat-prompt-input"
681	                  onChange={onChange}
682	                  onFocus={(e) => {
