697	              </SplitItem>
698	              <SplitItem className="ols-plugin__chat-prompt-submit">
699	                <Button className="ols-plugin__chat-prompt-button" icon={isStreaming ? <StopIcon /> : <PaperPlaneIcon />} type="submit" variant="primary" />
700	              </SplitItem>
701	            </Split>
702	          </Form>
703	          <div className="ols-plugin__chat-prompt-attachments">
704	            {attachments.keySeq().map((id: string) => {
