714	            })}
715	          </div>
716	
717	          <HelperText>
718	            <HelperTextItem className="ols-plugin__footer" variant="indeterminate">
719	              {t('Always review AI generated content prior to use.')}
720	            </HelperTextItem>
721	            <HelperTextItem className="ols-plugin__footer" variant="indeterminate">
